// // This module calculates the one's complement of a 4-bit signed integer.
module top_module(
    input signed [3:0] a,
    output reg signed [3:0] b
);always @(*) begin
    if (a[3] == 0) begin // positive number
        b = a;
    end else begin // negative number
        b = ~a + 1;
    end
end

endmodule
